components.content:
/* Carte principale - Sticky */
.sfc-card {
  position: sticky;
  top: 20px;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 12px;
  padding: 24px;
  font-family: 'Segoe UI', Roboto, sans-serif;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
}
.sfc-card h3 {
  font-size: 18px;
  font-weight: 700;
  color: #111827;
  margin: 0 0 4px;
}
.sfc-card .sfc-subtitle {
  font-size: 13.5px;
  color: #4b5563;
  margin: 0 0 18px;
  line-height: 1.5;
}
.sfc-row {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  margin-bottom: 12px;
  font-size: 13.5px;
  color: #374151;
  line-height: 1.5;
}
.sfc-row .sfc-ico {
  flex-shrink: 0;
  width: 20px;
  text-align: center;
  font-size: 15px;
  margin-top: 1px;
  color: #4b5563;
}
.sfc-row a {
  color: #3b82f6;
  text-decoration: none;
}
.sfc-row a:hover {
  text-decoration: underline;
}
.sfc-row strong {
  color: #111827;
  font-weight: 600;
}
.sfc-stitle {
  font-size: 16px;
  font-weight: 700;
  color: #111827;
  margin: 20px 0 12px;
  padding-top: 16px;
  border-top: 1px solid #e5e7eb;
}
.sfc-boxes {
  display: flex;
  gap: 10px;
  margin-bottom: 14px;
  width: 100%;
}
.sfc-box {
  flex: 1;
  background: #f9fafb;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 12px;
}
.sfc-box .sfc-lbl {
  font-size: 11.5px;
  color: #6b7280;
  font-weight: 500;
  margin: 0 0 6px;
  line-height: 1.3;
}
.sfc-box .sfc-val {
  font-size: 14px;
  font-weight: 700;
  color: #111827;
  margin: 0;
}
.sfc-box .sfc-sub {
  font-size: 11px;
  color: #9ca3af;
  font-weight: 400;
}
.sfc-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: #16a34a;
  font-size: 13px;
  font-weight: 600;
  text-decoration: none;
  cursor: pointer;
  margin-top: 5px;
}
.sfc-link:hover {
  text-decoration: underline;
}
.sfc-link-ico {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  background: #16a34a;
  color: #fff;
  border-radius: 50%;
  font-size: 11px;
  font-weight: 700;
}

