actions.customAction:
const recapDiv = document.getElementById("recapDisplay");
let list_of_datagrid = [];
let data_stock = [];
const exclude = ["button", "file", "container", "panel", "datagrid"];
const excludeKeys = ["luEtApprouve"];
const includesLabelForSelect = ["libelle", "label"];

// Collecte des données du formulaire
utils.eachComponent(
  form.components,
  (component, path) => {
    let splitted_path = path.split(".");
    let skip = false;

    // Vérifier que le composant n'est pas caché et qu'il respecte les autres conditions
    if (
      !exclude.includes(component.type) &&
      !excludeKeys.includes(component.key) &&
      !component.hidden && // Vérification pour exclure les éléments cachés
      ![null, undefined, "", [], {}, "[]", "{}"].includes(data[component.key]) &&
      !(typeof data[component.key] === "string" && ["null", "undefined", "", "[]", "{}"].includes(data[component.key]))
    ) {
      if (component.type === "datagrid") {
        list_of_datagrid.push(component.key);
      } else {
        if (
          splitted_path.length >= 2 &&
          list_of_datagrid.includes(splitted_path[splitted_path.length - 2])
        ) {
          skip = true;
        }
      }
      if (!skip) {
        data_stock.push({
          key: component.key,
          label: component.label,
          value: data[component.key] || (component.type === "datagrid" ? [] : ""),
          type: component.type,
          components: component.components || "",
        });
      }
    }
  },
  false
);

// Construction du tableau HTML
let ourTable = `
<style>
  .recap-container {
    width: 100%;
    margin: 0 auto;
  }
  .recap-table {
    width: 100%;
    border-collapse: collapse;
  }
  .recap-table thead th {
    background-color: #eeeeee;
    color: black;
    font-weight: bold;
    padding: 10px;
    border: 3px solid #ccc;
    text-align: center;
    font-family: poppins;
    font-size: 16px;
  }
  .recap-table th, .recap-table td {
    border: 3px solid #ccc;
    padding: 8px;
    text-align: left;
    font-size: 14px;
    font-family: poppins;
  }
  .recap-table td:first-child {
    width: 5%;
    text-align: center;
  }
  .recap-table td:nth-child(2) {
    width: 50%;
  }
  .recap-table td:last-child {
    width: 45%;
  }
  .datagrid-title, .select-key, .datetime-key, .default-key {
    font-weight: bold;
  }
</style>
<div class="recap-container">
  <table class="recap-table">
    <thead>
      <tr>
        <th>#</th>
        <th>Champs du formulaire</th>
        <th>Données saisies</th>
      </tr>
    </thead>
    <tbody>`;

let index = 1;

data_stock.forEach((elmt) => {
  if (Array.isArray(elmt.value) && elmt.type === "datagrid") {
    ourTable += `<tr><td colspan="3" class="datagrid-title"><b>${elmt.label}</b></td></tr>`;
    elmt.value.forEach((rowData) => {
      const keys = Object.keys(rowData);
      keys.forEach((key) => {
        let cmpnt = utils.getComponent(elmt.components, key);
        let formattedValue = rowData[key];
        if (typeof formattedValue === "string" && formattedValue.includes("T")) {
          const dateObj = new Date(formattedValue);
          formattedValue = dateObj.toLocaleDateString();
        }
        ourTable += `<tr><td>${index++}</td><td>&nbsp;&nbsp;&nbsp;&nbsp;${cmpnt.label}</td><td>${formattedValue}</td></tr>`;
      });
    });
  } else if (elmt.type === "select") {
    if (elmt.value !== undefined) {
      let valueToDisplay;
      if (typeof elmt.value === "object" && !Array.isArray(elmt.value)) {
        const includedPropertyName = includesLabelForSelect.find(
          (propName) => elmt.value[propName] !== undefined
        );
        valueToDisplay = includedPropertyName ? elmt.value[includedPropertyName] : "";
      } else if (Array.isArray(elmt.value)) {
        valueToDisplay = elmt.value.join(", ");
      } else {
        valueToDisplay = elmt.value;
      }
      ourTable += `<tr><td>${index++}</td><td><b>${elmt.label}</b></td><td>${valueToDisplay}</td></tr>`;
    }
  } else if (elmt.type === "datetime") {
    ourTable += `<tr><td>${index++}</td><td><b>${elmt.label}</b></td><td>${moment(elmt.value).format('LL')}</td></tr>`;
  } else if (elmt.type === "number") {
    ourTable += `<tr><td>${index++}</td><td><b>${elmt.label}</b></td><td>${elmt.value}</td></tr>`;
  } else {
    ourTable += `<tr><td>${index++}</td><td><b>${elmt.label}</b></td><td>${elmt.value}</td></tr>`;
  }
});

ourTable += `
    </tbody>
  </table>
  <hr>
</div>`;

// Insérer le tableau généré dans la div HTML
recapDiv.innerHTML = ourTable;
